}
fn _tcp_read_bytes(conn: TcpConn, n: usize) []const u8 {
    const _buf = std.heap.page_allocator.alloc(u8, n) catch @panic("OOM");
    var _total: usize = 0;
    while (_total < n) {
        const _got = std.posix.recv(conn.stream.handle, _buf[_total..], 0) catch break;
        if (_got == 0) break;
        _total += _got;
    }
